module top_module(
    input clk,
    input load,
    input [3:0] data_in,
    input shift_in,
    output [3:0] data_out,
    output shift_out
);reg [3:0] flipflop;

always @(posedge clk) begin
    if (load) begin
        flipflop <= data_in;
    end else begin
        flipflop <= {shift_in, flipflop[3:1]};
    end
end

assign data_out = flipflop;
assign shift_out = flipflop[3];

endmodule
